"use client";

import { cn } from "@/shared/lib/ui/cn";
import Image from "next/image";
import type { FC } from "react";
import { useEffect, useMemo, useState } from "react";

const WAVE_BG_SRC = "/new-design-images/carousel-waves.svg";

// --- Figma extracted assets (uploaded with 7-day expiry on the design side) ---
// Initial state (10%)
const IMG_STATE_1 = "/new-design-images/loading/state_1/img_state_1.svg";
const IMG_UNION_STATE_1 ="/new-design-images/loading/state_1/union_state_1.svg";

// Later state (53% and up)
const IMG_STATE_2 = "/new-design-images/loading/state_2/img_state_2.svg";
const IMG_LIQUID_LUXURY_STATE_2 ="/new-design-images/loading/state_2/liquid_luxury_state_2.svg";
const IMG_VECTOR_STATE_2 ="/new-design-images/loading/state_2/vector_state_2.svg";
const IMG_VECTOR_1_STATE_2 ="/new-design-images/loading/state_2/vector_1_state_2.svg";
const IMG_VECTOR_2_STATE_2 ="/new-design-images/loading/state_2/vector_2_state_2.svg";
const IMG_VECTOR_3_STATE_2 ="/new-design-images/loading/state_2/vector_3_state_2.svg";
const IMG_VECTOR_4_STATE_2 ="/new-design-images/loading/state_2/vector_4_state_2.svg";
const IMG_UNION_STATE_2 ="/new-design-images/loading/state_2/union_state_2.svg";
const IMG_VECTOR_5_STATE_2 ="/new-design-images/loading/state_2/vector_5_state_2.svg";


const WORDMARK_STATE_2 = [
  { src: IMG_VECTOR_STATE_2, width: 13.691, height: 32.596 },
  { src: IMG_VECTOR_1_STATE_2, width: 26.45, height: 33.248 },
  { src: IMG_VECTOR_2_STATE_2, width: 26.729, height: 32.596 },
  { src: IMG_VECTOR_3_STATE_2, width: 13.691, height: 32.596 },
  { src: IMG_VECTOR_STATE_2, width: 13.691, height: 32.596 },
  { src: IMG_VECTOR_5_STATE_2, width: 33.9, height: 33.9 },
  { src: IMG_VECTOR_4_STATE_2, width: 46.334, height: 33.248 },
] as const;

function clampProgress(progress: number): number {
  if (progress < 0) return 0;
  if (progress > 100) return 100;
  return progress;
}

interface UploadProgressScreenProps {
  className?: string;
  message?: string;

  /**
   * If provided, the screen will be rendered statically at this progress value.
   * If omitted, the progress animates from `initialProgress` to `targetProgress`.
   */
  progress?: number;
  initialProgress?: number;
  targetProgress?: number;
  durationMs?: number;
}

function FrameState1({ className }: { className?: string }) {
  return (
    <div
      className={cn("relative size-[8px] overflow-clip", className)}
      aria-hidden
    >
      <div className="absolute inset-0 size-[8px]">
        <Image
          src={IMG_STATE_1}
          alt=""
          fill
          unoptimized
          className="absolute block size-full max-w-none"
          aria-hidden
        />
      </div>
    </div>
  );
}

function CalendarState1({ src, className }: { src: string; className?: string }) {
  return (
    <div className={cn("relative overflow-clip", className)} aria-hidden>
      <div className="absolute inset-0">
        <Image
          src={src}
          alt=""
          fill
          unoptimized
          className="absolute block size-full max-w-none"
          aria-hidden
        />
      </div>
    </div>
  );
}

function WordmarkRow({ items }: { items: ReadonlyArray<{ src: string; width: number; height: number }> }) {
  return (
    <div className="flex items-end justify-center" aria-hidden>
      {items.map((item) => (
        <Image
          key={item.src}
          src={item.src}
          alt=""
          width={item.width}
          height={item.height}
          unoptimized
          aria-hidden
        />
      ))}
    </div>
  );
}

function LoadingIconState1({ showWordmark }: { showWordmark: boolean }) {
  return (
    <div className="-translate-x-1/2 -translate-y-1/2 absolute top-1/2 left-1/2 flex flex-col items-center gap-[13px]">
      <div className="relative h-[58px] w-[68px] shrink-0" aria-hidden>
        <div className="absolute inset-[-0.15%_-0.12%]">
          <Image
            src={IMG_UNION_STATE_1}
            alt=""
            fill
            unoptimized
            className="absolute block size-full max-w-none"
            aria-hidden
          />
        </div>
      </div>
      {showWordmark ? (
        <div className="flex w-[209px] flex-col items-center gap-[7px]" aria-hidden>
          <FrameState1 className="self-end" />
        </div>
      ) : null}
    </div>
  );
}

function LoadingIconState2() {
  return (
    <div className="-translate-x-1/2 -translate-y-1/2 absolute top-1/2 left-1/2 flex w-[209px] flex-col items-center gap-[13px]">
      <div className="relative h-[58px] w-[68px] shrink-0" aria-hidden>
        <div className="absolute inset-[-0.15%_-0.12%]">
          <Image
            src={IMG_UNION_STATE_2}
            alt=""
            fill
            unoptimized
            className="absolute block size-full max-w-none"
            aria-hidden
          />
        </div>
      </div>

      <div className="relative flex w-full shrink-0 flex-col items-center gap-[7px]">
        <div className="flex w-full items-end justify-center" aria-hidden>
          <WordmarkRow items={WORDMARK_STATE_2} />
          <div className="relative ml-2 size-[8px] overflow-clip" aria-hidden>
            <div className="absolute inset-0 size-[8px]">
              <Image
                src={IMG_STATE_2}
                alt=""
                fill
                unoptimized
                className="absolute block size-full max-w-none"
                aria-hidden
              />
            </div>
          </div>
        </div>

        <div className="relative h-[8.12px] w-[189.678px] shrink-0" aria-hidden>
          <Image
            src={IMG_LIQUID_LUXURY_STATE_2}
            alt=""
            fill
            unoptimized
            className="absolute block size-full max-w-none"
            aria-hidden
          />
        </div>
      </div>
    </div>
  );
}

export const UploadProgressScreen: FC<UploadProgressScreenProps> = ({
  className,
  message,
  progress: progressProp,
  initialProgress = 10,
  targetProgress = 53,
  durationMs = 5500,
}) => {
  const [progress, setProgress] = useState<number>(() =>
    typeof progressProp === "number" ? clampProgress(progressProp) : initialProgress,
  );

  const resolvedProgressProp = useMemo(
    () => (typeof progressProp === "number" ? clampProgress(progressProp) : null),
    [progressProp],
  );

  useEffect(() => {
    if (resolvedProgressProp !== null) {
      setProgress(resolvedProgressProp);
      return;
    }

    const start = Date.now();
    let lastProgressValue: number | null = null;

    let rafId = 0;

    const tick = () => {
      const elapsed = Date.now() - start;
      const t = Math.min(1, elapsed / durationMs);
      // Smooth ease-out curve for a nicer “loading” feel.
      const eased = 1 - (1 - t) ** 3;
      const next = clampProgress(initialProgress + (targetProgress - initialProgress) * eased);
      const rounded = Math.round(next);

      if (rounded !== lastProgressValue) {
        lastProgressValue = rounded;
        setProgress(rounded);
      }

      if (t < 1) {
        rafId = requestAnimationFrame(tick);
      }
    };

    rafId = requestAnimationFrame(tick);

    return () => cancelAnimationFrame(rafId);
  }, [
    resolvedProgressProp,
    durationMs,
    initialProgress,
    targetProgress,
  ]);

  const safeProgress = clampProgress(progress);
  const isLater = safeProgress >= 50;

  return (
    <section
      className={cn(
        "new-design relative flex h-full w-full items-center justify-center overflow-hidden bg-[#F5F3EF]",
        className,
      )}
      aria-label="Loading"
      aria-live="polite"
    >
      <Image
        src={WAVE_BG_SRC}
        alt=""
        fill
        unoptimized
        aria-hidden
        className="absolute inset-0 object-cover opacity-[0.18]"
      />

      {isLater ? <LoadingIconState2 /> : <LoadingIconState1 showWordmark={false} />}

      <div className="pointer-events-none absolute right-0 bottom-0 left-0 h-[10px]">
        <div
          className="absolute bottom-0 left-0 h-[10px] bg-[#021171]"
          style={{ width: `${safeProgress}%` }}
        />
      </div>

      <div
        className="-translate-x-1/2 -translate-y-1/2 pointer-events-none absolute bottom-[10px] left-0 text-center"
        style={{ left: `${safeProgress}%` }}
      >
        <span className="whitespace-nowrap font-extralight font-new-serif text-[#021171] text-[72px] not-italic leading-[1.1] tracking-[0px]">
          {safeProgress}%
        </span>
      </div>

      {message ? (
        <p className="-translate-x-1/2 absolute bottom-[30px] left-1/2 z-10 w-full max-w-[90%] text-center font-new-sans text-[#A8A29E] text-sm">
          {message}
        </p>
      ) : null}
    </section>
  );
};

