"use client";

import {
  useBuybackDetails,
  useCanRenewBuyback,
} from "@/shared/api/query-hooks/use-buyback";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { useCurrencyFormatter } from "@/shared/lib/hooks/use-currency-formatter";
import { getCdnUrl } from "@/shared/lib/utils/get-cdn-url";
import {
  type BuybackRequestDetail,
  BuybackRequestStatus,
} from "@/shared/types/buyback-request.types";
import { BuybackStatus, BuybackType } from "@/shared/types/buyback.types";
import { BackButton } from "@/shared/ui/back-button-new";
import { Loader } from "@/shared/ui/loader";
import { Button } from "@/shared/ui/shadcn/button";
import { Separator } from "@/shared/ui/shadcn/separator";
import { DeliveryInfoBreakdown } from "@/widgets/buyback-delivery-info-breakdown";
import { BuybackDetailsStepper } from "@/widgets/buyback-details-stepper-new";
import { FinalOfferBreakdown } from "@/widgets/buyback-final-offer-breakdown";
import { OfferDeclinedBlock } from "@/widgets/buyback-offer-declined-block";
import { OfferExpiredBlock } from "@/widgets/buyback-offer-expired-block";
import { OfferFinalOfferAcceptedBlock } from "@/widgets/buyback-offer-final-offer-accepted-block";
import { OfferPostAuthFailedBlock } from "@/widgets/buyback-offer-post-auth-failed";
import { PreAuthFailedBlock } from "@/widgets/buyback-pre-auth-failed-block";
import { Clock4Icon } from "lucide-react";
import { useSession } from "next-auth/react";
import dynamic from "next/dynamic";
